from vex import verify

@verify(checks=[
    'source_faithfulness',
    'hallucination',
    'context_relevance',
    'citation_accuracy'
])
def secure_rag_query(query: str):
    result = agent.run(query)
    return {
        'answer': result.content,
        'sources': result.sources,
        'citations': result.citations
    }

response = secure_rag_query('What is Vex?')
if response:
    print('Verified:', response['answer'])
else:
    print('Failed verification')

from vex import verify

@verify(
    checks=['source_faithfulness', 'hallucination'],
    max_retries=2,
    fallback='I cannot verify this response with available sources.'
)
def production_rag(query: str, max_retries: int = 2):
    for attempt in range(max_retries):
        result = agent.run(query)
        verified = verify_result(result)
        if verified:
            return result
    return {'error': 'Max retries exceeded'}

